package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.StringWriter;
import java.lang.reflect.Field;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithIgnoreSurroundingSpaces() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat result = csvFormat.withIgnoreSurroundingSpaces();

        // Then
        try {
            Field ignoreSurroundingSpacesField = CSVFormat.class.getDeclaredField("ignoreSurroundingSpaces");
            ignoreSurroundingSpacesField.setAccessible(true);
            boolean ignoreSurroundingSpacesValue = (boolean) ignoreSurroundingSpacesField.get(result);
            assertTrue(ignoreSurroundingSpacesValue);
        } catch (NoSuchFieldException | IllegalAccessException e) {
            fail("Exception occurred while accessing field: " + e.getMessage());
        }
    }
}
